#include<bits/stdc++.h>
using namespace std;
int a[30005];
int n;
bool check(int x){
	for(int i=1;i<=n;i++){
		if(a[i]==x)return false;
	}
	return true;
}
int main()
{
	cin>>n;
	a[1]=1;
	for(int i=2;i<=n;i++){
		if(a[i-1]-i>0&&check(a[i-1]-i)){
			a[i]=a[i-1]-i;
		}else{
			a[i]=a[i-1]+i;
		}
	}
	sort(a+1,a+n+1);
	for(int i=1;i<=n;i++)cout<<a[i]<<' ';
}
